import React from 'react';
import { Link } from 'react-router-dom';

const Dashboard: React.FC = () => {
    return (
        <div className="dashboard">
            <h1>Cybersecurity Intrusion Detection System</h1>
            <p>Welcome to the dashboard. Here you can view statistics and visualizations related to detected attacks.</p>
            <div className="stats">
                {/* Placeholder for statistics and visualizations */}
                <h2>Statistics</h2>
                <p>Total Attacks Detected: {/* Add dynamic data here */}</p>
                <p>Recent Alerts: {/* Add dynamic data here */}</p>
            </div>
            <div className="navigation">
                <h2>Navigation</h2>
                <Link to="/">Home</Link>
                <Link to="/upload">Upload Dataset</Link>
                <Link to="/results">View Results</Link>
            </div>
        </div>
    );
};

export default Dashboard;
